// ============================================
// TYPES
// ============================================

interface SearchParams {
  search?: string;
  category?: ProductCategory | "all";
  status?: ProductStatus | "all";
  sort?: string;
  order?: "asc" | "desc";
  page?: string;
  view?: "grid" | "list";
}

// ============================================
// DATA FETCHING
// ============================================

async function getProducts(
  farmerId: string,
  searchParams: SearchParams
) {
  const {
    search = "",
    category = "all",
    status = "all",
    sort = "createdAt",
    order = "desc",
    page = "1",
  } = searchParams;

  const pageSize = 12;
  const currentPage = parseInt(page, 10) || 1;
  const skip = (currentPage - 1) * pageSize;

  // Build where clause
  const where: any = {
    farmerId,
  };

  if (search) {
    where.OR = [
      { name: { contains: search, mode: "insensitive" } },
      { description: { contains: search, mode: "insensitive" } },
      { tags: { has: search } },
    ];
  }

  if (category && category !== "all") {
    where.category = category;
  }

  if (status && status !== "all") {
    where.status = status;
  }

  // Build orderBy
  const orderBy: any = {};
  const validSortFields = ["name", "pricePerUnit", "availableQty", "createdAt", "updatedAt"];
  if (validSortFields.includes(sort)) {
    orderBy[sort] = order;
  } else {
    orderBy.createdAt = "desc";
  }

  // Execute queries in parallel
  const [products, totalCount, stats] = await Promise.all([
    prisma.product.findMany({
      where,
      orderBy,
      skip,
      take: pageSize,
      include: {
        _count: {
          select: { orderItems: true },
        },
      },
    }),
    prisma.product.count({ where }),
    prisma.product.groupBy({
      by: ["status"],
      where: { farmerId },
      _count: true,
    }),
  ]);

  const totalPages = Math.ceil(totalCount / pageSize);

  // Calculate stats
  const statusCounts = {
    all: await prisma.product.count({ where: { farmerId } }),
    ACTIVE: 0,
    DRAFT: 0,
    OUT_OF_STOCK: 0,
    DISCONTINUED: 0,
  };

  stats.forEach((s) => {
    statusCounts[s.status as keyof typeof statusCounts] = s._count;
  });

  return {
    products,
    pagination: {
      currentPage,
      totalPages,
      totalCount,
      pageSize,
      hasNext: currentPage < totalPages,
      hasPrev: currentPage > 1,
    },
    stats: statusCounts,
  };
}

